function [nmbImg,imgNmb,nameLst2,bgLst] = fPhosShtLstV04(phsDir,phosN)%% Function fPhosShtLstV03.m %%%%%%%%%%% Function to get phosphor shot list, ver.3%% Kei Nakamura% Created on Friday, August 14th 2009.%% function imgExst = fPhosShtLstV01(phsDir,nmbSht);% give a list of image exist logic % against phosphor camera% imgExst: logic of image exist% espcDir: directory to check image% nmbSht: number of shots from trex logfile% camNmb: camera number% Modified on Friday, August 20th 2010.% ver.2: debug% Modified on Thursday, May 12th 2011.% ver.3: for new phosphors 1-3% ver.4: Wednesday, February 29th 2012.% new file name structure, GCP%%if phosN==1    dirNam = 'PhosphorScreen';    fileNam = '_PhosphorScreen_';elseif phosN==2    dirNam = 'PhosphorScreen2';    fileNam = '_PhosphorScreen2_';elseif phosN==3    dirNam = 'PhosphorScreen3';    fileNam = '_PhosphorScreen3_';endname = ['/*',fileNam,'*.png'];  % list of all images including BGnameLst = dir([phsDir,name]);         % information for Scan* file[nmbImg,dlt] = size(nameLst);   % number of images including BGimgNmb(1) = 0;      % image numberkk = 1;     % index for actual shot takenjj = 1;for jj=1:nmbImg    name = nameLst(jj).name;    pp1 = find(name=='_',1,'last');   % to get shot number from file name    pp2 = find(name=='.');    shtNmb = str2num(name(pp1+1:pp2-1));  % get shot number string    if shtNmb>0 % positive number for actual shot           nameLst2(kk).name = name;   % name list to output        imgNmb(kk) = shtNmb;        kk = kk +1;    elseif shtNmb<0        bgLst(jj).name = name;        jj = jj +1;    endendnmbImg = kk-1;
